import org.owasp.html.Sanitizers;
import java.util.Scanner;

public class XSSSecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize the user input to prevent XSS
        String sanitizedInput = Sanitizers.FORMATTING.and(Sanitizers.BLOCKS).and(Sanitizers.IMAGES).sanitize(userInput);

        System.out.println("Hello, " + sanitizedInput + "!");

        scanner.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
